const payload = $json.output ?? $json;
const citations = Array.isArray(payload.citations) ? payload.citations : [];
const githubAllowedPrefixes = [
  'https://github.com/GerardoACR/sassuolo2026',
  'https://raw.githubusercontent.com/GerardoACR/sassuolo2026',
  'documents/',
  'github://GerardoACR/sassuolo2026/'
];

const isNonEmpty = (value) => typeof value === 'string' && value.trim().length > 0;
const looksAllowedGithub = (value) => isNonEmpty(value) && githubAllowedPrefixes.some((prefix) => value.startsWith(prefix) || value.includes(prefix));
const hasGoodCitation = (citation) => {
  if (!citation || typeof citation !== 'object') return false;
  const sourceType = String(citation.source_type || '');
  if (!['google_sheet', 'github'].includes(sourceType)) return false;
  if (!isNonEmpty(citation.source_name)) return false;
  if (!isNonEmpty(citation.source_url)) return false;
  if (sourceType === 'github' && !looksAllowedGithub(String(citation.source_url))) return false;
  if (!isNonEmpty(citation.evidence_snippet)) return false;
  if (String(citation.evidence_snippet).trim().length < 20) return false;
  return true;
};

const grounded = payload.grounded === true;
const valid = grounded && isNonEmpty(payload.answer) && citations.length > 0 && citations.every(hasGoodCitation);

if (!valid) {
  return [{
    json: {
      text: 'Non ho trovato una risposta verificabile esclusivamente nella documentazione autorizzata. Per rispondere devo avere almeno una fonte valida con estratto ed evidenza tracciabile da Google Sheets o GitHub.',
      grounded: false,
      answer: 'Non ho trovato una risposta verificabile esclusivamente nella documentazione autorizzata.',
      citations: [],
      missing_information: 'Missing valid grounded citations from allowed documentation tools.',
      validation_failed: true
    }
  }];
}

const formattedSources = citations.map((citation, index) => {
  const label = `S${index + 1}`;
  return `[${label}] ${citation.source_name} - ${citation.source_url}\nEvidence: ${citation.evidence_snippet}`;
}).join('\n\n');

return [{
  json: {
    text: `${String(payload.answer).trim()}\n\nFonti:\n${formattedSources}`,
    grounded: true,
    answer: String(payload.answer).trim(),
    citations,
    missing_information: String(payload.missing_information || '').trim(),
    validation_failed: false
  }
}];
